const html = $input.item.json.data || '';
const studentName = $node['Set Website Info'].json.studentName;
const url = $node['Set Website Info'].json.websiteUrl;

const prompt = `Evaluate this student website for SEO optimization.

STUDENT: ${studentName}
URL: ${url}

HTML CONTENT:
${html.substring(0, 3000)}

EVALUATE THESE CRITERIA:
1. H1 heading optimization (includes keywords?)
2. Meta description (present and 150-160 chars?)
3. Image alt text (present on all images?)
4. Keyword usage (appropriate density?)
5. Mobile responsiveness indicators
6. Page structure (proper heading hierarchy?)

Provide:
- Strengths found
- Issues to fix
- Specific recommendations
- Priority actions (top 3)

Return as JSON:
{
  "student_name": "${studentName}",
  "strengths": ["strength 1", "strength 2"],
  "issues": ["issue 1", "issue 2"],
  "recommendations": ["rec 1", "rec 2"],
  "priority_actions": ["action 1", "action 2", "action 3"]
}`;

return { json: { prompt, studentName, url } };

const response = $input.item.json.response;
const studentName = $node['Build SEO Analysis Prompt'].json.studentName;
const url = $node['Build SEO Analysis Prompt'].json.url;

let analysis;
try {
  const clean = response.replace(/```json/g, '').replace(/```/g, '').trim();
  analysis = JSON.parse(clean);
} catch (e) {
  return { json: { error: 'Failed to parse response', raw: response } };
}

const report = `
WEBSITE SEO ANALYSIS
===================

Student: ${studentName}
URL: ${url}
Date: ${new Date().toLocaleDateString()}

✓ STRENGTHS
${analysis.strengths.map((s, i) => `  ${i+1}. ${s}`).join('\n')}

⚠ ISSUES TO FIX
${analysis.issues.map((s, i) => `  ${i+1}. ${s}`).join('\n')}

💡 RECOMMENDATIONS
${analysis.recommendations.map((s, i) => `  ${i+1}. ${s}`).join('\n')}

🎯 PRIORITY ACTIONS
${analysis.priority_actions.map((s, i) => `  ${i+1}. ${s}`).join('\n')}

NOTE: This is automated technical feedback.
Use it to improve your website before final submission.
===================
`;

return { json: { report, studentName, url } };
